# solution.py
"""Team Collaboration Manager.

Standard library only, ASCII only, Python 3.12. The authoritative contract is
the bundled test_solution.py; this implementation follows it exactly.
"""

import copy
import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    pass


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
class Attachment:
    def __init__(self, filename, size, uploaded_by, uploaded_at):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at


class User:
    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at


class Project:
    def __init__(self, id, name, description, start_date, end_date, owner_id):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id


class Task:
    def __init__(self, id, project_id, title, status=TaskStatus.NOT_STARTED,
                 assignee_id=None, deadline=None):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = None
        self.completed_at = None


class Message:
    def __init__(self, id, author_id, body, project_id, task_id, parent_id,
                 attachments, created_at):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments
        self.created_at = created_at
        self.edited_at = None


class Rating:
    def __init__(self, id, rater_id, ratee_id, score, feedback, task_id,
                 created_at):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at


# ---------------------------------------------------------------------------
# Internal store base sharing the manager lock
# ---------------------------------------------------------------------------
class _Store:
    """A thread-shared in-memory collection.

    Every store created by a manager shares the manager's single ``RLock`` so
    that operations spanning multiple stores remain mutually consistent.
    """

    def __init__(self, lock):
        self._lock = lock
        self._items = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """In-memory manager for users, projects, tasks, messages and reports.

    All public operations are guarded by a single re-entrant lock shared with
    the six sub-stores, and every getter returns deep copies so callers cannot
    mutate internal state. Entity ids are drawn from one monotonically
    increasing counter shared across all entity types.
    """

    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._next_id = 1

        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # assignee_id -> set of task ids
        self._assignee_index = {}
        # ratee_id -> list of Rating
        self._ratings = {}

    # -- helpers -----------------------------------------------------------
    def _allocate_id(self):
        with self._lock:
            new_id = self._next_id
            self._next_id += 1
            return new_id

    def _require_user(self, user_id):
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        msg = self.messages._items.get(message_id)
        if msg is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return msg

    def _validate_username(self, username):
        if username is None or not str(username).strip():
            raise ValidationError("username required")

    def _validate_email(self, email):
        if email is None or not str(email) or "@" not in str(email):
            raise ValidationError("valid email required")

    def _check_unique_username(self, username, exclude_id=None):
        for u in self.users._items.values():
            if u.id != exclude_id and u.username == username:
                raise DuplicateError("duplicate username")

    def _check_unique_email(self, email, exclude_id=None):
        for u in self.users._items.values():
            if u.id != exclude_id and u.email == email:
                raise DuplicateError("duplicate email")

    # ------------------------------------------------------------------
    # User methods
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        """Create and store a new user, returning a copy of it."""
        with self._lock:
            self._validate_username(username)
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("invalid role")
            self._check_unique_username(username)
            self._check_unique_email(email)
            user = User(self._allocate_id(), username, email, role, self._now())
            self.users._items[user.id] = user
            return copy.deepcopy(user)

    def get_user(self, user_id):
        """Return a deep copy of the user, or raise NotFoundError."""
        with self._lock:
            return copy.deepcopy(self._require_user(user_id))

    def list_users(self):
        """Return deep copies of all users ordered by id."""
        with self._lock:
            return [copy.deepcopy(u)
                    for u in sorted(self.users._items.values(),
                                    key=lambda x: x.id)]

    def update_user(self, user_id, username=None, email=None, role=None):
        """Update the provided fields of a user and return a copy."""
        with self._lock:
            user = self._require_user(user_id)
            if username is not None:
                self._validate_username(username)
                self._check_unique_username(username, exclude_id=user_id)
            if email is not None:
                self._validate_email(email)
                self._check_unique_email(email, exclude_id=user_id)
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("invalid role")
            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id):
        """Delete a user that owns no projects and has no open tasks."""
        with self._lock:
            self._require_user(user_id)
            for p in self.projects._items.values():
                if p.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for t in self.tasks._items.values():
                if t.assignee_id == user_id and t.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks")
            # remove from assignee index
            self._assignee_index.pop(user_id, None)
            self._ratings.pop(user_id, None)
            del self.users._items[user_id]

    # ------------------------------------------------------------------
    # Project methods
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id,
                        description=""):
        """Create a project owned by an existing user and return a copy."""
        with self._lock:
            self._require_user(owner_id)
            if name is None or not str(name).strip():
                raise ValidationError("name required")
            if end_date < start_date:
                raise ValidationError("end_date before start_date")
            project = Project(self._allocate_id(), name, description,
                              start_date, end_date, owner_id)
            self.projects._items[project.id] = project
            return copy.deepcopy(project)

    def get_project(self, project_id):
        """Return a deep copy of the project, or raise NotFoundError."""
        with self._lock:
            return copy.deepcopy(self._require_project(project_id))

    def list_projects(self):
        """Return deep copies of all projects ordered by id."""
        with self._lock:
            return [copy.deepcopy(p)
                    for p in sorted(self.projects._items.values(),
                                    key=lambda x: x.id)]

    def update_project(self, project_id, name=None, description=None,
                       start_date=None, end_date=None):
        """Update the provided fields of a project and return a copy."""
        with self._lock:
            project = self._require_project(project_id)
            if name is not None and not str(name).strip():
                raise ValidationError("name required")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date before start_date")
            if name is not None:
                project.name = name
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            return copy.deepcopy(project)

    def delete_project(self, project_id):
        """Delete a project along with its tasks and related messages."""
        with self._lock:
            self._require_project(project_id)
            task_ids = [t.id for t in self.tasks._items.values()
                        if t.project_id == project_id]
            for tid in task_ids:
                task = self.tasks._items.pop(tid)
                if task.assignee_id is not None:
                    s = self._assignee_index.get(task.assignee_id)
                    if s is not None:
                        s.discard(tid)
            task_id_set = set(task_ids)
            msg_ids = [m.id for m in self.messages._items.values()
                       if m.project_id == project_id
                       or (m.task_id is not None and m.task_id in task_id_set)]
            for mid in msg_ids:
                del self.messages._items[mid]
            del self.projects._items[project_id]

    # ------------------------------------------------------------------
    # Task methods
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        """Create a task within a project and return a copy."""
        with self._lock:
            project = self._require_project(project_id)
            if assignee_id is not None:
                self._require_user(assignee_id)
            if title is None or not str(title).strip():
                raise ValidationError("title required")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline before project start")
            task = Task(self._allocate_id(), project_id, title,
                        assignee_id=assignee_id, deadline=deadline)
            self.tasks._items[task.id] = task
            if assignee_id is not None:
                self._assignee_index.setdefault(assignee_id, set()).add(task.id)
            return copy.deepcopy(task)

    def get_task(self, task_id):
        """Return a deep copy of the task, or raise NotFoundError."""
        with self._lock:
            return copy.deepcopy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        """Return deep copies of a project's tasks ordered by id."""
        with self._lock:
            self._require_project(project_id)
            return [copy.deepcopy(t)
                    for t in sorted(self.tasks._items.values(),
                                    key=lambda x: x.id)
                    if t.project_id == project_id]

    def list_tasks_by_assignee(self, assignee_id):
        """Return deep copies of a user's assigned tasks ordered by id."""
        with self._lock:
            self._require_user(assignee_id)
            ids = self._assignee_index.get(assignee_id, set())
            tasks = [self.tasks._items[tid] for tid in ids
                     if tid in self.tasks._items]
            return [copy.deepcopy(t)
                    for t in sorted(tasks, key=lambda x: x.id)]

    def _set_assignee(self, task, new_assignee_id):
        old = task.assignee_id
        if old is not None:
            s = self._assignee_index.get(old)
            if s is not None:
                s.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._assignee_index.setdefault(new_assignee_id, set()).add(task.id)

    def assign_task(self, task_id, assignee_id):
        """Assign a task to a user and return a copy."""
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id):
        """Move a task to a different assignee and return a copy."""
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id):
        """Remove any assignee from a task and return a copy."""
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        """Set or clear a task deadline and return a copy."""
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline before project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        """Transition a task's status, updating start/complete timestamps."""
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("invalid status")
            task = self._require_task(task_id)
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # ------------------------------------------------------------------
    # Messaging methods
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        """Post a message to exactly one project or task and return a copy."""
        with self._lock:
            self._require_user(author_id)
            if project_id is None and task_id is None:
                raise ValidationError("project_id or task_id required")
            if project_id is not None and task_id is not None:
                raise ValidationError("only one of project_id/task_id")
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            att_tuples = attachments or []
            body_str = body if body is not None else ""
            if not str(body_str).strip() and len(att_tuples) == 0:
                raise ValidationError("empty message")
            if parent_id is not None:
                self._require_message(parent_id)
            now = self._now()
            built = []
            for filename, data in att_tuples:
                built.append(Attachment(filename, len(data), author_id, now))
            msg = Message(self._allocate_id(), author_id, body_str,
                          project_id, task_id, parent_id, built, now)
            self.messages._items[msg.id] = msg
            return copy.deepcopy(msg)

    def edit_message(self, message_id, editor_id, new_body):
        """Edit a message body (author only) and return a copy."""
        with self._lock:
            msg = self._require_message(message_id)
            if msg.author_id != editor_id:
                raise AuthorizationError("not the author")
            body_str = new_body if new_body is not None else ""
            if not str(body_str).strip() and len(msg.attachments) == 0:
                raise ValidationError("empty message")
            msg.body = body_str
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(self, message_id, uploader_id, filename, data):
        """Append an attachment to a message (author only) and return a copy."""
        with self._lock:
            msg = self._require_message(message_id)
            if msg.author_id != uploader_id:
                raise AuthorizationError("not the author")
            if filename is None or not str(filename):
                raise ValidationError("filename required")
            msg.attachments.append(
                Attachment(filename, len(data), uploader_id, self._now()))
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id):
        """Return deep copies of a project's messages ordered by id."""
        with self._lock:
            self._require_project(project_id)
            return [copy.deepcopy(m)
                    for m in sorted(self.messages._items.values(),
                                    key=lambda x: x.id)
                    if m.project_id == project_id]

    def list_messages_by_task(self, task_id):
        """Return deep copies of a task's messages ordered by id."""
        with self._lock:
            self._require_task(task_id)
            return [copy.deepcopy(m)
                    for m in sorted(self.messages._items.values(),
                                    key=lambda x: x.id)
                    if m.task_id == task_id]

    def delete_message(self, message_id, requester_id):
        """Delete a message (author only)."""
        with self._lock:
            msg = self._require_message(message_id)
            if msg.author_id != requester_id:
                raise AuthorizationError("not the author")
            del self.messages._items[message_id]

    # ------------------------------------------------------------------
    # Performance methods
    # ------------------------------------------------------------------
    def _tasks_for_user(self, user_id):
        ids = self._assignee_index.get(user_id, set())
        return [self.tasks._items[tid] for tid in ids
                if tid in self.tasks._items]

    def _status_breakdown(self, tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(1 for t in tasks
                          if t.status == TaskStatus.IN_PROGRESS)
        not_started = sum(1 for t in tasks
                          if t.status == TaskStatus.NOT_STARTED)
        return total, completed, in_progress, not_started

    def _rating_stats(self, user_id):
        ratings = self._ratings.get(user_id, [])
        count = len(ratings)
        average = (sum(r.score for r in ratings) / count) if count else 0.0
        return ratings, count, average

    def get_completion_rate(self, user_id):
        """Return the fraction of a user's tasks that are completed."""
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks
                            if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        """Return mean seconds to complete tasks, or None if none completed."""
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            durations = []
            for t in tasks:
                if (t.status == TaskStatus.COMPLETED
                        and t.started_at is not None
                        and t.completed_at is not None):
                    durations.append(
                        (t.completed_at - t.started_at).total_seconds())
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="",
                      task_id=None):
        """Record a 1..5 rating of one user by another and return a copy."""
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("cannot rate self")
            if not isinstance(score, int) or score < 1 or score > 5:
                raise ValidationError("score must be 1..5")
            if task_id is not None:
                self._require_task(task_id)
            rating = Rating(self._allocate_id(), rater_id, ratee_id, score,
                            feedback, task_id, self._now())
            self._ratings.setdefault(ratee_id, []).append(rating)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id):
        """Return count, average and copies of a user's received ratings."""
        with self._lock:
            self._require_user(user_id)
            ratings, count, average = self._rating_stats(user_id)
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        """Return aggregated task and rating statistics for a user."""
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            total, completed, in_progress, not_started = \
                self._status_breakdown(tasks)
            completion_rate = (completed / total) if total else 0.0
            avg_time = self.get_average_completion_time(user_id)
            _, rating_count, rating_average = self._rating_stats(user_id)
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Report methods
    # ------------------------------------------------------------------
    def _user_summary(self, user_id, tasks):
        total, completed, in_progress, not_started = \
            self._status_breakdown(tasks)
        completion_rate = (completed / total) if total else 0.0
        return {
            "user_id": user_id,
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": completion_rate,
        }

    def project_progress_report(self, project_id):
        """Return a progress report for a single project."""
        with self._lock:
            self._require_project(project_id)
            tasks = [t for t in self.tasks._items.values()
                     if t.project_id == project_id]
            total = len(tasks)
            status_counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            for t in tasks:
                status_counts[t.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (completed / total) if total else 0.0
            now = self._now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None and t.deadline < now
                and t.status != TaskStatus.COMPLETED)
            per_assignee = {}
            assignees = {t.assignee_id for t in tasks
                         if t.assignee_id is not None}
            for aid in assignees:
                user_tasks = [t for t in tasks if t.assignee_id == aid]
                per_assignee[aid] = self._user_summary(aid, user_tasks)
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        """Return per-assignee performance rows, optionally scoped to a project."""
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scope = [t for t in self.tasks._items.values()
                         if t.project_id == project_id]
            else:
                scope = list(self.tasks._items.values())
            rows = []
            user_ids = sorted({t.assignee_id for t in scope
                               if t.assignee_id is not None})
            for uid in user_ids:
                user_tasks = [t for t in scope if t.assignee_id == uid]
                rows.append(self._user_summary(uid, user_tasks))
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        """Return a per-task performance report for a single user."""
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(self._tasks_for_user(user_id), key=lambda x: x.id)
            total = len(tasks)
            completed = sum(1 for t in tasks
                            if t.status == TaskStatus.COMPLETED)
            task_rows = []
            for t in tasks:
                task_rows.append({
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                })
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "tasks": task_rows,
            }

    # ------------------------------------------------------------------
    # Export
    # ------------------------------------------------------------------
    def export_report(self, report, fmt):
        """Serialize a report dict to CSV text or PDF bytes."""
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("invalid report format")
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    def _export_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list):
            header = []
            for row in rows:
                if isinstance(row, dict):
                    for key in row.keys():
                        if key not in header:
                            header.append(key)
            if not header:
                header = ["report_type"]
            writer.writerow(header)
            for row in rows:
                if isinstance(row, dict):
                    writer.writerow([row.get(col, "") for col in header])
        else:
            keys = []
            values = []
            for key, value in report.items():
                if isinstance(value, (dict, list)):
                    continue
                keys.append(key)
                values.append(value)
            if not keys:
                keys = ["report_type"]
                values = [report.get("report_type", "")]
            writer.writerow(keys)
            writer.writerow(values)
        return output.getvalue()

    def _export_pdf(self, report):
        lines = []
        rtype = report.get("report_type", "report")
        lines.append("Report: {0}".format(rtype))
        for key, value in report.items():
            if isinstance(value, (dict, list)):
                continue
            lines.append("{0}: {1}".format(key, value))
        text = "  ".join(lines)
        text = "".join(ch if 32 <= ord(ch) < 127 else " " for ch in text)
        text = text.replace("\\", " ").replace("(", " ").replace(")", " ")

        content = "BT /F1 12 Tf 50 750 Td ({0}) Tj ET".format(text)
        content_bytes = content.encode("ascii", "replace")

        objects = []
        objects.append(b"<< /Type /Catalog /Pages 2 0 R >>")
        objects.append(b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
        objects.append(
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>")
        objects.append(
            b"<< /Length " + str(len(content_bytes)).encode("ascii")
            + b" >>\nstream\n" + content_bytes + b"\nendstream")
        objects.append(
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>")

        buf = bytearray()
        buf += b"%PDF-1.4\n"
        offsets = []
        for i, obj in enumerate(objects, start=1):
            offsets.append(len(buf))
            buf += str(i).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"
        xref_pos = len(buf)
        count = len(objects) + 1
        buf += b"xref\n"
        buf += b"0 " + str(count).encode("ascii") + b"\n"
        buf += b"0000000000 65535 f \n"
        for off in offsets:
            buf += ("{0:010d} 00000 n \n".format(off)).encode("ascii")
        buf += b"trailer\n"
        buf += (b"<< /Size " + str(count).encode("ascii")
                + b" /Root 1 0 R >>\n")
        buf += b"startxref\n"
        buf += str(xref_pos).encode("ascii") + b"\n"
        buf += b"%%EOF\n"
        return bytes(buf)
